namespace LifeOS.Systems
{
    public class TimelineCoordinator
    {
        readonly RealTimelineStore _realTimeline;
        readonly SimulationTimelineStore _simulationTimeline;

        public TimelineViewMode ViewMode { get; set; } = TimelineViewMode.Real;

        public RealTimelineStore RealTimeline => _realTimeline;
        public SimulationTimelineStore SimulationTimeline => _simulationTimeline;

        public TimelineCoordinator(
            RealTimelineStore realTimeline = null,
            SimulationTimelineStore simulationTimeline = null)
        {
            _realTimeline = realTimeline ?? new RealTimelineStore();
            _simulationTimeline = simulationTimeline ?? new SimulationTimelineStore();
        }

        public List<ActivityEntry> GetVisibleEntries()
        {
            return ViewMode == TimelineViewMode.Real
                ? _realTimeline.GetAllOrdered()
                : _simulationTimeline.GetOrderedEntries();
        }

        public ActivityEntry AdoptSimulatedPlan(string simulatedEntryId)
        {
            var simulatedEntry = _simulationTimeline.FindById(simulatedEntryId);
            if (simulatedEntry == null || simulatedEntry.kind != TimelineKind.Simulated)
            {
                return null;
            }

            var plannedStartUtc = simulatedEntry.GetPlannedStartUtc(_simulationTimeline.Anchor.AnchorUtc);
            var plannedEntry = _realTimeline.AddPlanned(simulatedEntry, plannedStartUtc);
            _simulationTimeline.Remove(simulatedEntryId);
            return plannedEntry;
        }

        public List<ActivityEntry> AdoptAllSimulatedPlans()
        {
            var adopted = new List<ActivityEntry>();
            var simulatedEntries = _simulationTimeline.GetOrderedEntries();

            foreach (var simulatedEntry in simulatedEntries)
            {
                var plannedEntry = AdoptSimulatedPlan(simulatedEntry.id);
                if (plannedEntry != null)
                {
                    adopted.Add(plannedEntry);
                }
            }

            return adopted;
        }

        public ActivityEntry ConfirmPlannedActivity(string realEntryId, DateTime? actualStartUtc = null)
        {
            var entry = _realTimeline.FindById(realEntryId);
            if (entry == null || entry.status != ActivityStatus.Planned)
            {
                return null;
            }

            _realTimeline.MarkAsLogged(realEntryId, actualStartUtc ?? entry.GetStartTimeUtc());
            return _realTimeline.FindById(realEntryId);
        }

        public void SaveAll()
        {
            _realTimeline.Save();
            _simulationTimeline.Save();
        }
    }
}

