namespace LifeOS.Systems
{
    public class RealTimelineStore
    {
        const string FileName = "real_timeline.json";

        readonly string _filePath;
        readonly TimelineDatabase _database = new TimelineDatabase();

        public IReadOnlyList<ActivityEntry> Entries => _database.entries;

        public RealTimelineStore(string storageDirectory = null)
        {
            var directory = storageDirectory ?? JsonFileStorage.GetDefaultStorageDirectory();
            _filePath = System.IO.Path.Combine(directory, FileName);
            Load();
        }

        public ActivityEntry LogActivity(
            string title,
            float duration,
            string category,
            int mood,
            int energy,
            DateTime? startTimeUtc = null)
        {
            var entry = ActivityEntry.CreateReal(
                title,
                duration,
                category,
                mood,
                energy,
                startTimeUtc ?? DateTime.UtcNow,
                ActivityStatus.Logged);

            _database.entries.Add(entry);
            Save();
            return entry;
        }

        public ActivityEntry AddPlanned(ActivityEntry source, DateTime plannedStartUtc)
        {
            var entry = ActivityEntry.CreateReal(
                source.title,
                source.duration,
                source.category,
                source.mood,
                source.energy,
                plannedStartUtc,
                ActivityStatus.Planned);

            _database.entries.Add(entry);
            Save();
            return entry;
        }

        public bool MarkAsLogged(string id, DateTime? actualStartUtc = null)
        {
            var entry = FindById(id);
            if (entry == null || entry.kind != TimelineKind.Real)
            {
                return false;
            }

            entry.status = ActivityStatus.Logged;
            if (actualStartUtc.HasValue)
            {
                entry.SetStartTimeUtc(actualStartUtc.Value);
            }

            Save();
            return true;
        }

        public bool Update(ActivityEntry updatedEntry)
        {
            var index = _database.entries.FindIndex(entry => entry.id == updatedEntry.id);
            if (index < 0 || updatedEntry.kind != TimelineKind.Real)
            {
                return false;
            }

            _database.entries[index] = updatedEntry;
            Save();
            return true;
        }

        public bool Remove(string id)
        {
            var removed = _database.entries.RemoveAll(entry => entry.id == id) > 0;
            if (removed)
            {
                Save();
            }

            return removed;
        }

        public ActivityEntry FindById(string id)
        {
            return _database.entries.FirstOrDefault(entry => entry.id == id);
        }

        public List<ActivityEntry> GetBetween(DateTime startUtc, DateTime endUtc)
        {
            return _database.entries
                .Where(entry => entry.kind == TimelineKind.Real)
                .Where(entry =>
                {
                    var start = entry.GetStartTimeUtc();
                    return start >= startUtc.ToUniversalTime() && start <= endUtc.ToUniversalTime();
                })
                .OrderBy(entry => entry.GetStartTimeUtc())
                .ToList();
        }

        public List<ActivityEntry> GetByStatus(ActivityStatus status)
        {
            return _database.entries
                .Where(entry => entry.kind == TimelineKind.Real && entry.status == status)
                .OrderBy(entry => entry.GetStartTimeUtc())
                .ToList();
        }

        public List<ActivityEntry> GetAllOrdered()
        {
            return _database.entries
                .Where(entry => entry.kind == TimelineKind.Real)
                .OrderBy(entry => entry.GetStartTimeUtc())
                .ToList();
        }

        public void Save()
        {
            JsonFileStorage.Save(_filePath, _database);
        }

        public void Load()
        {
            var loaded = JsonFileStorage.Load<TimelineDatabase>(_filePath);
            _database.entries = loaded.entries ?? new List<ActivityEntry>();
        }
    }
}

