            if (removed)
            {
                Save();
            }

            return removed;
        }

        public ActivityEntry FindById(string id)
        {
            return _database.entries.FirstOrDefault(entry => entry.id == id);
        }

        public List<ActivityEntry> GetOrderedEntries()
        {
            return _database.entries
                .Where(entry => entry.kind == TimelineKind.Simulated)
                .OrderBy(entry => entry.plannedOffsetMinutes)
                .ToList();
        }

