        {
            _database.entries.Clear();
            Save();
        }

        public void SetAnchor(DateTime anchorUtc)
        {
            _anchor.SetAnchor(anchorUtc);
            Save();
        }

        public void Save()
        {
            var payload = new SimulationTimelineDatabase
            {
                anchorTimeUtc = _anchor.AnchorTimeUtcString,
                entries = _database.entries
            };

            JsonFileStorage.Save(_filePath, payload);
        }

        public void Load()
        {
            var loaded = JsonFileStorage.Load<SimulationTimelineDatabase>(_filePath);
            _database.entries = loaded.entries ?? new List<ActivityEntry>();

            if (!string.IsNullOrEmpty(loaded.anchorTimeUtc))
            {
                _anchor.SetAnchor(DateTime.Parse(
                    loaded.anchorTimeUtc,
                    null,
                    System.Globalization.DateTimeStyles.RoundtripKind));
            }
        }
